const name = safe(profileItem.name || profileItem.login);
const bio = safe(profileItem.bio);
const location = safe(profileItem.location);
const publicRepos = profileItem.public_repos || 0;
const followers = profileItem.followers || 0;

const topRepos = reposItem.sort((a,b) => (b.stargazers_count - a.stargazers_count)).slice(0, 8);
const languages = {};
reposItem.forEach(r => { if (r.language) languages[r.language] = (languages[r.language] || 0) + 1; });
const topLangs = Object.entries(languages).sort((a,b) => b[1]-a[1]).map(([l,c]) => `${l}(${c})`).join(', ');
const totalStars = reposItem.reduce((s,r) => s + (r.stargazers_count || 0), 0);
const repoText = topRepos.map((r,i) =>
  `${i+1}. ${safe(r.name)} [${safe(r.language||'N/A')}] ★${r.stargazers_count}\n   ${safe(r.description||'No description')}\n   ${safe(r.html_url)}`
).join('\n\n');

