Username: ${safe(profileItem.login)}
Name: ${name}
Bio: ${bio||'(empty)'}
Public repos: ${publicRepos} | Stars: ${totalStars} | Followers: ${followers}
Languages: ${topLangs||'(none)'}

TOP REPOS:
${repoText||'(none)'}`;

