const prev = $json;

let topJobDesc = '';
let topJobTitle = '';
let topJobCompany = '';
try {
  const srj = $('Score_Rank_Jobs').first().json;
  topJobDesc = srj.topJobDesc || '';
  topJobTitle = srj.topJobTitle || '';
  topJobCompany = srj.topJobCompany || '';
} catch(e) {}

const jobDesc = (topJobDesc || prev.userMessage || '').toLowerCase();

const stopWords = new Set(['the','and','or','a','an','to','of','in','for','is','are','will','with','as','on','at','by','be']);
function extractKeywords(text) {
  if (!text) return {};
  return text.replace(/[^a-z0-9\s-]/g, ' ').split(/\s+/).filter(w => w.length > 3 && !stopWords.has(w)).reduce((acc, w) => { acc[w] = (acc[w] || 0) + 1; return acc; }, {});
}

const wordFreq = extractKeywords(jobDesc);
const sortedKeys = Object.entries(wordFreq).sort((a, b) => b[1] - a[1]).slice(0, 20).map(([word]) => word);

const techPattern = /\b(Python|SQL|Java|React|Node\.?js|AWS|Azure|GCP|Docker|Kubernetes|Tableau|Power\s?BI|Excel|Git|REST|API|Machine\s?Learning|ML|NLP|TensorFlow|PyTorch|pandas|numpy|Spark|MongoDB|PostgreSQL|MySQL)\b/gi;
const techMatches = [...(topJobDesc || prev.userMessage || '').matchAll(techPattern)].map(m => m[0]).filter((v, i, a) => a.indexOf(v) === i).slice(0, 12);

const keywordSummary = techMatches.length ? `Key technologies: ${techMatches.join(', ')}. Key themes: ${sortedKeys.slice(0, 8).join(', ')}.` : `Key themes: ${sortedKeys.slice(0, 12).join(', ')}.`;

return [{ json: { userMessage: prev.userMessage, sessionId: prev.sessionId, jdKeywords: keywordSummary, topJobTitle, topJobCompany, topJobDesc: topJobDesc || prev.userMessage } }];

const item = $input.first().json;
const msg = $('Read_Message').first().json.userMessage || '';
const sessionId = $('Read_Message').first().json.sessionId;

// Parse company name from the cover letter prompt
let topJobCompany = '';
let topJobTitle = '';
const companyMatch = msg.match(/Company:\s*([^\n]+)/i);
if (companyMatch) topJobCompany = companyMatch[1].trim();
const roleMatch = msg.match(/Role:\s*([^\n]+)/i);
if (roleMatch) topJobTitle = roleMatch[1].trim();

// Fallback to Score_Rank_Jobs if job search was done earlier
if (!topJobCompany) {
  try { const srj = $('Score_Rank_Jobs').first().json; topJobCompany = srj.topJobCompany || ''; topJobTitle = srj.topJobTitle || ''; } catch(e) {}
}

// Extract company fact from SerpAPI result
let companyFact = '';
try {
  const results = item.organic_results || [];
  if (results.length > 0) {
    const snippets = results.map(r => r.snippet || '').filter(s => s.length > 30);
    if (snippets.length > 0) {
      companyFact = snippets[0].split(/[.!?]/)[0].trim();
      if (companyFact.length > 150) companyFact = companyFact.slice(0, 150) + '...';
    }
  }
} catch(e) { companyFact = ''; }

return [{ json: {
  userMessage: msg,
  sessionId,
  topJobCompany,
  topJobTitle,
  companyFact: companyFact || '',
  hasFact: companyFact.length > 0
} }];

