try { if (!params.role) params = $('Extract_Job_Params_LinkedIn').first().json; } catch(e) {}
const role = String(params.role || '').toLowerCase();
const loc = String(params.location || 'india').toLowerCase();
const boostWords = ['intern','fresher','entry','junior','trainee','graduate','analyst','associate'];
function safeStr(val) { if (val === null || val === undefined) return ''; if (typeof val === 'string') return val; if (typeof val === 'object') { return val.city || val.name || val.text || val.label || JSON.stringify(val); } return String(val); }
function parseSalaryLPA(s) { s = safeStr(s); if (!s) return null; const range = s.match(/(\d+(?:\.\d+)?)\s*(?:-|to|–)\s*(\d+(?:\.\d+)?)\s*(?:lpa|lakh)/i); if (range) return { min: parseFloat(range[1]), max: parseFloat(range[2]) }; return null; }
function scoreJob(j) { const titleLower = safeStr(j.title).toLowerCase(); const text = (titleLower + ' ' + safeStr(j.description) + ' ' + safeStr(j.skills)).toLowerCase(); const locLower = safeStr(j.location).toLowerCase(); let s = 0; for (const k of boostWords) if (text.includes(k)) s += 10; const roleWords = role.split(' ').filter(w => w.length > 2); for (const rw of roleWords) if (titleLower.includes(rw)) s += 25; for (const rw of roleWords) if (text.includes(rw)) s += 5; if (locLower.includes(loc)) s += 30; if (locLower.includes('remote')) s += 15; if (j.postedAt) { try { const daysAgo = (Date.now() - new Date(j.postedAt)) / 86400000; if (daysAgo < 1) s += 40; else if (daysAgo < 3) s += 25; else if (daysAgo < 7) s += 15; } catch(e) {} } return s; }
if (items.length === 1 && items[0].json._empty) { const e = items[0].json; return [{ json: { jobList: '', jobCount: 0, noResults: true, role: safeStr(e.role), location: safeStr(e.location), sessionId: safeStr(e.sessionId), userMessage: safeStr(e.userMessage) } }]; }
const valid = items.filter(i => i.json && i.json.title && !i.json.error && !i.json._empty);
if (!valid.length) { return [{ json: { jobList: '', jobCount: 0, noResults: true, role, location: loc, sessionId: safeStr(params.sessionId), userMessage: safeStr(params.userMessage) } }]; }
const scored = valid.map(i => ({ ...i.json, _score: scoreJob(i.json) })).sort((a, b) => b._score - a._score).slice(0, 5);
const list = scored.map((j, i) => { let age = 'recently'; try { if (j.postedAt) age = Math.round((Date.now() - new Date(j.postedAt)) / 86400000) + 'd ago'; } catch(e) {} return [`JOB ${i+1}:`, `Title: ${safeStr(j.title)}`, `Company: ${safeStr(j.company)} [${j.source}]`, `Location: ${safeStr(j.location)}`, `Posted: ${age}`, `Salary: ${safeStr(j.salary) || 'Not disclosed'}`, `Apply: ${safeStr(j.url) || 'Search on ' + j.source}`, ...(safeStr(j.description) ? [`Description: ${safeStr(j.description).slice(0, 500)}`] : [])].join('\n'); }).join('\n\n---\n\n');
const top = scored[0];
return [{ json: { jobList: list, jobCount: scored.length, noResults: false, topJobTitle: safeStr(top?.title), topJobCompany: safeStr(top?.company), topJobUrl: safeStr(top?.url), topJobDesc: safeStr(top?.description || top?.skills).slice(0, 600), role, location: loc, sessionId: safeStr(params.sessionId), userMessage: safeStr(params.userMessage) } }];

const allItems = $input.all();
function safeStr(val) { if (val === null || val === undefined) return ''; if (typeof val === 'string') return val.trim(); if (typeof val === 'object') { return (val.city || val.name || val.text || val.label || JSON.stringify(val)).trim(); } return String(val).trim(); }
function stripHtml(s) { return s ? s.replace(/<[^>]+>/g, " ").replace(/&nbsp;/g," ").replace(/&amp;/g,"&").replace(/&lt;/g,"<").replace(/&gt;/g,">").replace(/\s{2,}/g," ").trim() : ""; }
function parsePlaceholder(placeholders, type) { if (!Array.isArray(placeholders)) return ''; const p = placeholders.find(function(x) { return x.type === type; }); return p ? safeStr(p.label) : ''; }
function parsePostedAt(raw) { if (!raw) return ''; const s = safeStr(raw); if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s; const lower = s.toLowerCase(); if (lower.indexOf('today') > -1 || lower.indexOf('hour') > -1) { return new Date().toISOString(); } const daysMatch = s.match(/(\d+)\s*day/i); if (daysMatch) { const d = new Date(); d.setDate(d.getDate() - parseInt(daysMatch[1])); return d.toISOString(); } return ''; }
function normalise(j) {
  const isNaukri = !!(j.company_name || j.tags_and_skills || j.job_id);
  const isLinkedIn = !!(j.companyName || j.attributes);
  const isGoogleSearch = !!(j.displayedUrl || j.type === 'organic');

  if (isNaukri) {
    const placeholders = j.placeholders || [];
    var rawUrl = j.jd_url || (j.static_url ? 'https://www.naukri.com/' + j.static_url : '') || '';
    return {
      title: safeStr(j.title),
      company: safeStr(j.company_name),
      location: parsePlaceholder(placeholders, 'location'),
      salary: parsePlaceholder(placeholders, 'salary') || 'Not disclosed',
      description: safeStr(j.tags_and_skills || j.snippet),
      url: safeStr(rawUrl),
      postedAt: parsePostedAt(j.footer_placeholder_label || j.postedAt),
      skills: safeStr(j.tags_and_skills),
      source: 'Naukri'
    };
  }

  if (isLinkedIn) {
    return {
      title: safeStr(j.title),
      company: safeStr(j.companyName || j.company),
      location: safeStr(j.location),
      salary: safeStr(j.salary) || 'Not disclosed',
      description: stripHtml(safeStr(j.description || j.descriptionText || j.jobDescription || j.shortDescription || j.descriptionHtml || '')),
      url: safeStr(j.url || j.jobUrl || j.applyUrl),
      postedAt: parsePostedAt(j.postedAt || j.publishedAt),
      source: 'LinkedIn'
    };
  }

  if (isGoogleSearch) {
    // Extract company name from title if format is "Role - Company | Site"
    const titleParts = safeStr(j.title).split(/\s[-|]\s/);
    const company = titleParts.length > 1 ? titleParts[titleParts.length - 1].replace(/naukri\.com|linkedin\.com/i, '').trim() : '';
    return {
      title: titleParts[0] || safeStr(j.title),
      company: company,
      location: safeStr(j.location) || '',
      salary: 'Not disclosed',
      description: safeStr(j.description || j.snippet),
      url: safeStr(j.url),
      postedAt: '',
      source: 'Google/Naukri'
    };
  }

  // Generic fallback
  return {
    title: safeStr(j.title || j.jobTitle),
    company: safeStr(j.company || j.companyName),
    location: safeStr(j.location),
    salary: safeStr(j.salary) || 'Not disclosed',
    description: safeStr(j.description || j.snippet),
    url: safeStr(j.url || j.jobUrl),
    postedAt: parsePostedAt(j.postedAt || j.datePosted),
    source: 'Other'
  };
}
const seen = new Set(); const deduped = [];
for (var i = 0; i < allItems.length; i++) { const j = allItems[i].json; if (!j || j.error || j._empty) continue; const n = normalise(j); if (!n.title && !n.company) continue; const key = n.title.toLowerCase().replace(/\s+/g,'_') + '__' + n.company.toLowerCase().replace(/\s+/g,'_'); if (seen.has(key)) continue; seen.add(key); deduped.push({ json: n }); }
