function toHtml(text) {
  return text.split('\n').map(line => {
    const t = line.trim();
    if (!t) return '<div style="margin:5px 0"></div>';
    if (/^━+/.test(t)) {
      const label = t.replace(/━/g, '').trim();
      return `<h2 style="font-size:11px;font-weight:bold;border-bottom:1.5px solid #555;margin:14px 0 4px;padding-bottom:3px;text-transform:uppercase;letter-spacing:0.8px">${label}</h2>`;
    }
    if (t.startsWith('•') || t.startsWith('-')) {
      return `<div style="margin:2px 0 2px 14px;font-size:10.5px;line-height:1.5">${t}</div>`;
    }
    return `<p style="margin:2px 0;font-size:10.5px;line-height:1.6">${t}</p>`;
  }).join('');
}

