const agentOutput = ($input.first().json.output || '').trim();
const sessionId = $('Read_Message').first().json.sessionId;

// Extract just the COVER LETTER section for the PDF
const clMatch = agentOutput.match(/━+\s*COVER LETTER\s*━+\n([\s\S]*?)(?=━{3,}|$)/i);
const coverLetterText = clMatch ? clMatch[1].trim() : agentOutput;

// Parse lines into structured HTML
const lines = coverLetterText.split('\n').map(l => l.trim()).filter(l => l.length > 0);

let html = '';
let inBody = false;

for (let i = 0; i < lines.length; i++) {
  const l = lines[i];
  // Subject line
  if (/^Subject:/i.test(l)) {
    html += `<p style="margin:0 0 20px;font-size:11.5px;font-weight:bold">${l}</p>`;
    inBody = true;
  }
  // Dear / salutation
  else if (/^Dear /i.test(l)) {
    html += `<p style="margin:0 0 14px;font-size:11.5px">${l}</p>`;
  }
  // Closing (Yours/Sincerely/Regards)
  else if (/^(Yours|Sincerely|Regards|Best|Warm)/i.test(l)) {
    html += `<p style="margin:18px 0 4px;font-size:11.5px">${l}</p>`;
  }
  // Bullet points
  else if (l.startsWith('•') || l.startsWith('-')) {
    html += `<p style="margin:2px 0 2px 16px;font-size:11px;line-height:1.6">${l}</p>`;
  }
  // Header lines (sender/recipient block — first few lines before Subject)
  else if (!inBody && i < 8) {
    html += `<p style="margin:0 0 3px;font-size:11px;color:#444">${l}</p>`;
  }
  // Body paragraphs
  else {
    html += `<p style="margin:0 0 14px;font-size:11.5px;line-height:1.8;text-align:justify">${l}</p>`;
  }
}

